from flask import Flask, jsonify

app = Flask(__name__)

# Database simulation
products = [
    {'id': 1, 'name': 'Laptop', 'price': 999},
    {'id': 2, 'name': 'Mouse', 'price': 25}
]

@app.route('/')
def index():
    return "Welcome to the Store API! Visit /api/products"

@app.route('/api/products')
def get_products():
    # jsonify converts Python lists/dicts into real JSON responses
    return jsonify(products)

